const first = $input.all()[0]?.json ?? {};
const triggerMode = Object.keys(first).length > 0 ? 'schedule' : 'manual';
const batchSize = Number($env.TELEGRAM_NOTIFICATION_BATCH_SIZE || 10);
const retryDelayMinutes = Number($env.TELEGRAM_NOTIFICATION_RETRY_DELAY_MINUTES || 30);
const lockTimeoutMinutes = Number($env.TELEGRAM_NOTIFICATION_LOCK_TIMEOUT_MINUTES || 30);
const startedAt = new Date().toISOString();
return [{
  json: {
    workflow_name: 'Send Opportunity Notifications',
    triggered_by: triggerMode,
    started_at_utc: startedAt,
    profile_slug: $env.TELEGRAM_NOTIFICATION_PROFILE_SLUG || '',
    batch_size: Number.isFinite(batchSize) && batchSize > 0 ? batchSize : 10,
    retry_delay_minutes: Number.isFinite(retryDelayMinutes) && retryDelayMinutes > 0 ? retryDelayMinutes : 30,
    lock_timeout_minutes: Number.isFinite(lockTimeoutMinutes) && lockTimeoutMinutes > 0 ? lockTimeoutMinutes : 30,
    bot_name: $env.TELEGRAM_BOT_NAME || 'Ri assistant',
    inline_actions_enabled: String($env.TELEGRAM_INLINE_ACTIONS_ENABLED || 'false').toLowerCase() === 'true',
    lock_token: `telegram-delivery:${startedAt}`,
  },
}];

