const context = $('Init Delivery Context').first().json;
const toArray = (value) => {
  if (!value) {
    return [];
  }
  if (Array.isArray(value)) {
    return value;
  }
  if (typeof value === 'string') {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }
  return [];
};
const mapOpportunityType = (value) => {
  switch (value) {
    case 'vacancy':
    case 'part_time':
      return 'job';
    case 'freelance_order':
    case 'one_time_task':
      return 'freelance';
    case 'project':
    case 'automation_request':
    case 'n8n_task':
    case 'telegram_bot_task':
    case 'openai_task':
    case 'business_automation_task':
      return 'project';
    default:
      return value || 'other';
  }
};
const formatBudget = (minValue, maxValue, currency) => {
  const min = minValue ?? null;
  const max = maxValue ?? null;
  const code = currency || '';
  if (min === null && max === null) {
    return 'не указана';
  }
  if (min !== null && max !== null) {
    return `${min}-${max}${code ? ` ${code}` : ''}`;
  }
  if (min !== null) {
    return `от ${min}${code ? ` ${code}` : ''}`;
  }
  return `до ${max}${code ? ` ${code}` : ''}`;
};
const renderList = (title, items, emptyLabel = '— нет явных пунктов') => {
  const normalized = items.filter(Boolean).slice(0, 2);
  return `${title}\n${normalized.length ? normalized.map((item) => `— ${String(item).trim()}`).join('\n') : emptyLabel}`;
};
return $input.all().map((item) => {
  const whyFit = toArray(item.json.why_fit);
  const risks = toArray(item.json.risks);
  const score = Number(item.json.opportunity_score || 0);
  const title = String(item.json.title || 'Без названия').trim();
  const sourceName = String(item.json.source_name || item.json.source_type || 'unknown').trim();
  const action = String(item.json.recommended_action || 'review_manually').trim();
  const opportunityType = mapOpportunityType(String(item.json.opportunity_type || '').trim());
  const budgetText = formatBudget(item.json.budget_min, item.json.budget_max, item.json.currency);
  const lines = [
    '🔥 Новая возможность',
    '',
    `Тип: ${opportunityType}`,
    `Источник: ${sourceName}`,
    `Название: ${title}`,
    `Score: ${Math.round(score)}`,
    `Действие: ${action}`,
    '',
    renderList('Почему подходит:', whyFit),
    '',
    renderList('Риски:', risks),
    '',
    `Оплата: ${budgetText}`,
  ];
  if (item.json.url) {
    lines.push('', `Ссылка: ${item.json.url}`);
  }
  const keyboard = [];
  if (item.json.url) {
    keyboard.push([{ text: 'Открыть', url: item.json.url }]);
  }
  if (context.inline_actions_enabled) {
    keyboard.push([
      { text: 'Сохранить', callback_data: `notif:${item.json.notification_id}:save` },
      { text: 'Не интересно', callback_data: `notif:${item.json.notification_id}:not_interested` }
    ]);
    keyboard.push([
      { text: 'Позже', callback_data: `notif:${item.json.notification_id}:later` }
    ]);
  }
  return {
    json: {
      notification_id: item.json.notification_id,
      retry_delay_minutes: context.retry_delay_minutes,
      chat_id: String(item.json.chat_id),
      telegram_request: {
        chat_id: String(item.json.chat_id),
        text: lines.join('\n'),
        disable_web_page_preview: true,
        reply_markup: keyboard.length ? { inline_keyboard: keyboard } : undefined,
      },
    },
  };
});

const source = $('Build Telegram Message').item.json;
const payload = $json ?? {};
if (payload.error) {
  return [{
    json: {
      notification_id: source.notification_id,
      retry_delay_minutes: source.retry_delay_minutes,
      has_error: true,
      error_message: payload.error.message || 'Telegram API request failed.',
      error_details: { error: payload.error },
    },
  }];
}
if (payload.ok !== true || !payload.result?.message_id) {
  return [{
    json: {
      notification_id: source.notification_id,
      retry_delay_minutes: source.retry_delay_minutes,
      has_error: true,
      error_message: 'Telegram API returned an unsuccessful response.',
      error_details: { response: payload },
    },
  }];
}
return [{
  json: {
    notification_id: source.notification_id,
    retry_delay_minutes: source.retry_delay_minutes,
    has_error: false,
    telegram_message_id: String(payload.result.message_id),
    telegram_response: payload,
  },
}];
